package org.apache.commons.jxpath.ri.compiler;

import org.apache.commons.jxpath.ri.EvalContext;

/**
 * Implementation of Expression for the operation "&gt;".
 *
 * @author Dmitri Plotnikov
 * @version $Revision$ $Date$
 */
public class CoreOperationGreaterThan extends CoreOperationCompare {

    public CoreOperationGreaterThan(Expression arg1, Expression arg2) {
        super(arg1, arg2);
    }

    public Object computeValue(EvalContext context) {
        return greaterThan(context, args[0], args[1]) ? Boolean.TRUE : Boolean.FALSE;
    }

    /**
     * Performs greater-than comparison, handling nodesets properly
     */
    protected boolean greaterThan(EvalContext context, Expression left, Expression right) {
        Object l = left.compute(context);
        Object r = right.compute(context);

        if (l instanceof org.apache.commons.jxpath.ri.axes.InitialContext) {
            ((EvalContext) l).reset();
        }

        if (l instanceof org.apache.commons.jxpath.ri.axes.SelfContext) {
            l = ((EvalContext) l).getSingleNodePointer();
        }

        if (r instanceof org.apache.commons.jxpath.ri.axes.InitialContext) {
            ((EvalContext) r).reset();
        }

        if (r instanceof org.apache.commons.jxpath.ri.axes.SelfContext) {
            r = ((EvalContext) r).getSingleNodePointer();
